"use client"

import { useEffect, useState } from "react"
import {
  File,
  FileText,
  Image,
  Receipt,
  Trash2,
  Download,
  Loader2,
  Plus,
  FileJson,
} from "lucide-react"
import FileUploadDialog from "./FileUploadDialog"
import { useFileManagement } from "@/lib/useFileManagement"

interface FileManagerProps {
  workspaceId: string
  propertyId: string
  uploadedBy: string
  contractorId?: string
}

const fileTypeIcons: Record<string, React.ReactNode> = {
  pdf: <FileText className="w-5 h-5 text-red-500" />,
  photo: <Image className="w-5 h-5 text-blue-500" />,
  invoice: <Receipt className="w-5 h-5 text-green-500" />,
  contractor_document: <FileJson className="w-5 h-5 text-purple-500" />,
}

const fileTypeLabels: Record<string, string> = {
  pdf: "PDF",
  photo: "Photo",
  invoice: "Invoice",
  contractor_document: "Contractor Doc",
}

export default function FileManager({
  workspaceId,
  propertyId,
  uploadedBy,
  contractorId,
}: FileManagerProps) {
  const [isUploadDialogOpen, setIsUploadDialogOpen] = useState(false)
  const [selectedFilter, setSelectedFilter] = useState<string | null>(null)

  const { files, isLoading, error, uploadFile, fetchFiles, deleteFile } =
    useFileManagement()

  // Load files on mount
  useEffect(() => {
    loadFiles()
  }, [selectedFilter])

  const loadFiles = async () => {
    try {
      await fetchFiles({
        workspaceId,
        propertyId,
        fileType: selectedFilter || undefined,
        contractorId: contractorId || undefined,
      })
    } catch (err) {
      console.error("Failed to load files:", err)
    }
  }

  const handleUpload = async (
    file: File,
    fileType: string,
    description?: string
  ) => {
    await uploadFile(
      file,
      fileType,
      workspaceId,
      propertyId,
      uploadedBy,
      description,
      contractorId
    )
    loadFiles()
  }

  const handleDelete = async (fileId: string) => {
    if (confirm("Are you sure you want to delete this file?")) {
      await deleteFile(fileId)
    }
  }

  const handleDownload = (fileUrl: string, fileName: string) => {
    const link = document.createElement("a")
    link.href = fileUrl
    link.download = fileName
    link.click()
  }

  const filterOptions = [
    { value: "pdf", label: "PDFs" },
    { value: "photo", label: "Photos" },
    { value: "invoice", label: "Invoices" },
    { value: "contractor_document", label: "Contractor Docs" },
  ]

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-50">
            File Management
          </h3>
          <p className="text-sm text-gray-600 dark:text-gray-400">
            {files.length} file{files.length !== 1 ? "s" : ""} uploaded
          </p>
        </div>

        <button
          onClick={() => setIsUploadDialogOpen(true)}
          className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
        >
          <Plus className="w-4 h-4" />
          Upload File
        </button>
      </div>

      {/* Upload Dialog */}
      <FileUploadDialog
        isOpen={isUploadDialogOpen}
        onClose={() => setIsUploadDialogOpen(false)}
        onUpload={handleUpload}
        isLoading={isLoading}
      />

      {/* Filters */}
      <div className="flex gap-2 flex-wrap">
        <button
          onClick={() => setSelectedFilter(null)}
          className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
            selectedFilter === null
              ? "bg-blue-600 text-white"
              : "bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600"
          }`}
        >
          All Files
        </button>
        {filterOptions.map((option) => (
          <button
            key={option.value}
            onClick={() => setSelectedFilter(option.value)}
            className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
              selectedFilter === option.value
                ? "bg-blue-600 text-white"
                : "bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600"
            }`}
          >
            {option.label}
          </button>
        ))}
      </div>

      {/* Error Message */}
      {error && (
        <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-700 rounded-lg text-sm text-red-700 dark:text-red-300">
          {error}
        </div>
      )}

      {/* Loading State */}
      {isLoading && (
        <div className="flex items-center justify-center py-8">
          <Loader2 className="w-6 h-6 animate-spin text-blue-600" />
        </div>
      )}

      {/* File List */}
    {files.map((file) => (
  <div
    key={file._id}
    className="flex items-center justify-between p-4 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg hover:shadow-md transition-shadow"
  >
    <div className="flex items-center gap-3 flex-1 min-w-0">
      
      {/* ✅ Show actual image for photos, icon for others */}
      {file.fileType === "photo" ? (
        <img
          src={file.fileUrl}
          alt={file.fileName}
          className="w-12 h-12 object-cover rounded-lg border border-gray-200 dark:border-gray-700 flex-shrink-0"
        />
      ) : (
        <div className="w-12 h-12 flex items-center justify-center bg-gray-100 dark:bg-gray-700 rounded-lg flex-shrink-0">
          {fileTypeIcons[file.fileType] || <File className="w-5 h-5" />}
        </div>
      )}

      <div className="flex-1 min-w-0">
        <p className="text-sm font-medium text-gray-900 dark:text-gray-50 truncate">
          {file.fileName}
        </p>
        <div className="flex items-center gap-2 text-xs text-gray-600 dark:text-gray-400">
          <span className="bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded">
            {fileTypeLabels[file.fileType]}
          </span>
          <span>{(file.fileSize / 1024 / 1024).toFixed(2)} MB</span>
          <span>Uploaded by {file.uploadedBy}</span>
          <span>{new Date(file.createdAt).toLocaleDateString()}</span>
        </div>
        {file.description && (
          <p className="text-xs text-gray-500 dark:text-gray-500 mt-1">
            {file.description}
          </p>
        )}
      </div>
    </div>

    {/* Actions */}
    <div className="flex items-center gap-2 ml-4">
      {/* ✅ For photos, open in new tab instead of download */}
      {file.fileType === "photo" ? (
        <button
          onClick={() => window.open(file.fileUrl, "_blank")}
          className="p-2 text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition-colors"
          title="View full image"
        >
          <Image className="w-4 h-4" />
        </button>
      ) : (
        <button
          onClick={() => handleDownload(file.fileUrl, file.fileName)}
          className="p-2 text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition-colors"
          title="Download"
        >
          <Download className="w-4 h-4" />
        </button>
      )}

      <button
        onClick={() => handleDelete(file._id)}
        className="p-2 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded transition-colors"
        title="Delete"
      >
        <Trash2 className="w-4 h-4" />
      </button>
    </div>
  </div>
))}

      {/* Empty State */}
      {!isLoading && files.length === 0 && (
        <div className="text-center py-8">
          <File className="w-12 h-12 text-gray-300 dark:text-gray-600 mx-auto mb-2" />
          <p className="text-gray-600 dark:text-gray-400">No files uploaded</p>
          <p className="text-sm text-gray-500 dark:text-gray-500">
            Click "Upload File" to add files
          </p>
        </div>
      )}
    </div>
  )
}










