/**
 * FIXED EXPORT UTILS - Handle undefined values
 * ============================================
 */

import jsPDF from "jspdf"
import html2canvas from "html2canvas"
import Papa from "papaparse"

/**
 * Helper: Safe value display
 */
function safeValue(value: any, defaultText = "N/A"): string {
  if (value === null || value === undefined) {
    return defaultText
  }
  if (typeof value === "number") {
    return value.toLocaleString()
  }
  return String(value)
}

/**
 * Helper: Format currency
 */
function formatCurrency(value: any): string {
  if (!value && value !== 0) return "$0"
  const num = Number(value)
  if (isNaN(num)) return "$0"
  return `$${num.toLocaleString()}`
}

/**
 * Export property details as PDF - FIXED
 */
export async function exportPropertyPDF(
  propertyAddress: string,
  htmlElement: HTMLElement,
  propertyData: any = {}
) {
  try {
    console.log("🔵 Starting PDF export for:", propertyAddress)

    // Always use text PDF for reliability
    return exportPropertyPDFText(propertyAddress, propertyData)
  } catch (error) {
    console.error("❌ PDF Export Error:", error)
    throw new Error(
      `Failed to export PDF: ${error instanceof Error ? error.message : "Unknown error"}`
    )
  }
}

/**
 * Text-based PDF export - MAIN EXPORT METHOD
 */
export function exportPropertyPDFText(
  propertyAddress: string,
  data: any = {}
) {
  try {
    console.log("📄 Creating PDF for property:", propertyAddress)

    // Ensure data exists
    if (!data) {
      data = {}
    }

    const pdf = new jsPDF({
      orientation: "portrait",
      unit: "mm",
      format: "a4",
    })

    let yPosition = 20
    const pageWidth = pdf.internal.pageSize.getWidth()
    const margin = 15
    const lineHeight = 6
    const maxWidth = pageWidth - margin * 2

    // Helper to add text with auto-page breaking
    const addText = (text: string = "", isBold = false, fontSize = 11) => {
      if (yPosition > 270) {
        pdf.addPage()
        yPosition = 20
      }

      pdf.setFontSize(fontSize)
      pdf.setFont("helvetica", isBold ? "bold" : "normal")

      const lines = pdf.splitTextToSize(text, maxWidth)

      lines.forEach((line: string) => {
        if (yPosition > 270) {
          pdf.addPage()
          yPosition = 20
        }
        pdf.text(line, margin, yPosition)
        yPosition += lineHeight
      })
    }

    const addSection = (title: string) => {
      yPosition += 4
      addText(title, true, 13)
      yPosition += 2
    }

    // ============================================================
    // TITLE
    // ============================================================
    addText("PROPERTY DETAILS REPORT", true, 16)
    addText(`Generated: ${new Date().toLocaleString()}`, false, 9)
    yPosition += 3

    // ============================================================
    // PROPERTY INFORMATION
    // ============================================================
    addSection("Property Information")

    const propertyAddress_clean = safeValue(
      data.property?.address || propertyAddress,
      "N/A"
    )
    const city = safeValue(data.property?.city, "N/A")
    const state = safeValue(data.property?.state, "N/A")
    const zipCode = safeValue(data.property?.zipCode, "N/A")

    addText(`Address: ${propertyAddress_clean}`)
    addText(`City: ${city}`)
    addText(`State: ${state}`)
    addText(`Zip Code: ${zipCode}`)

    // ============================================================
    // EXECUTION COSTS
    // ============================================================
    const costs =
      data.workspace?.executionCosts || data.phase1?.costs || {}

    if (Object.keys(costs).length > 0) {
      addSection("Execution Costs")

      const purchasePrice = formatCurrency(costs.purchasePrice)
      const rehabCost = formatCurrency(costs.rehabCost)
      const holdingCosts = formatCurrency(costs.holdingCosts)
      const closingCosts = formatCurrency(costs.closingCosts)
      const totalCosts = formatCurrency(costs.totalCosts)

      addText(`Purchase Price: ${purchasePrice}`)
      addText(`Rehab Cost: ${rehabCost}`)
      addText(`Holding Costs: ${holdingCosts}`)
      addText(`Closing Costs: ${closingCosts}`)
      addText(`Total Costs: ${totalCosts}`, true)
    }

    // ============================================================
    // PROJECT STATUS
    // ============================================================
    if (data.workspace?.stage) {
      addSection("Project Status")
      addText(`Current Stage: ${safeValue(data.workspace.stage, "N/A")}`)
    }

    // ============================================================
    // ARV INFORMATION
    // ============================================================
    const arv = data.phase1?.arv

    if (arv) {
      addSection("ARV (After Repair Value)")

      const baseArv = formatCurrency(arv.baseArv)
      const finalArv = formatCurrency(arv.finalArv)

      addText(`Base ARV: ${baseArv}`)
      addText(`Final ARV: ${finalArv}`)

      // Adjustment steps
      if (arv.adjustmentSteps && Array.isArray(arv.adjustmentSteps)) {
        if (arv.adjustmentSteps.length > 0) {
          addText("Adjustment Steps:", false, 10)
          arv.adjustmentSteps.forEach((step: any, index: number) => {
            if (step && typeof step === "object") {
              const stepText = Object.entries(step)
                .map(([key, val]) => `${key}: ${safeValue(val)}`)
                .join(" | ")
              addText(`  ${index + 1}. ${stepText}`)
            }
          })
        }
      }
    }

    // ============================================================
    // CHECKLIST
    // ============================================================
    if (data.checklist && Array.isArray(data.checklist) && data.checklist.length > 0) {
      addSection("Due Diligence Checklist")

      const completed = data.checklist.filter((item: any) => item?.completed).length
      const total = data.checklist.length

      addText(`Progress: ${completed} of ${total} completed`, false, 10)
      yPosition += 2

      data.checklist.forEach((item: any) => {
        if (!item) return

        const status = item.completed ? "✓" : "○"
        const label = safeValue(item.label, "Unknown Item")

        addText(`${status} ${label}`)

        if (item.notes) {
          addText(`   Notes: ${safeValue(item.notes)}`)
        }

        if (item.dueDate) {
          const dueDate = new Date(item.dueDate).toLocaleDateString()
          addText(`   Due: ${dueDate}`)
        }
      })
    }

    // ============================================================
    // WORKSPACE INFO (if available)
    // ============================================================
    if (data.workspace) {
      addSection("Workspace Information")

      const workspaceId = safeValue(data.workspace._id, "N/A")
      const stage = safeValue(data.workspace.stage, "N/A")

      addText(`Workspace ID: ${workspaceId}`)
      addText(`Stage: ${stage}`)
    }

    // ============================================================
    // FOOTER
    // ============================================================
    yPosition += 5
    addText("---", false, 10)
    addText(
      `End of Report | ${new Date().toLocaleString()}`,
      false,
      8
    )

    // Save PDF
    const filename = `${propertyAddress.replace(/\s+/g, "-")}-details.pdf`
    pdf.save(filename)

    console.log("✅ PDF exported successfully:", filename)
    return { success: true, filename }
  } catch (error) {
    console.error("❌ PDF export failed:", error)
    throw new Error(
      `Failed to export PDF: ${error instanceof Error ? error.message : "Unknown error"}`
    )
  }
}

/**
 * Export property details as CSV
 */
export function exportPropertyCSV(data: any, propertyAddress: string) {
  try {
    console.log("🔵 Starting CSV export for:", propertyAddress)

    if (!data) {
      data = {}
    }

    const flattenedData = flattenObject(data)
    const csv = Papa.unparse([flattenedData])

    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" })
    const link = document.createElement("a")
    const url = URL.createObjectURL(blob)

    link.setAttribute("href", url)
    const filename = `${propertyAddress.replace(/\s+/g, "-")}-details.csv`
    link.setAttribute("download", filename)
    link.style.visibility = "hidden"

    document.body.appendChild(link)
    link.click()

    setTimeout(() => {
      document.body.removeChild(link)
      URL.revokeObjectURL(url)
    }, 100)

    console.log("✅ CSV EXPORTED SUCCESSFULLY")
    return { success: true, filename }
  } catch (error) {
    console.error("❌ CSV Export Error:", error)
    throw new Error(
      `Failed to export CSV: ${error instanceof Error ? error.message : "Unknown error"}`
    )
  }
}

