"use client"

import { useEffect, useState } from "react"
import { useParams } from "next/navigation"
import { AdminLayout } from "@/components/admin-layout"
import { 
  ArrowLeft, 
  CheckCircle2, 
  Circle, 
  AlertCircle, 
  MapPin, 
  Loader2,
  Calendar,
  FileText,
  CheckSquare,
  DollarSign,
  Users,
  Edit2,
  Save,
  X,
} from "lucide-react"
import Link from "next/link"
import { Input } from "@/components/ui/input"

// Import Milestone 2 components
import TasksManager from "@/components/execution/TasksManager"
import ContractorsManager from "@/components/execution/ContractorsManager"
import TimelineTracker from "@/components/execution/TimelineTracker"
import InspectionTracker from "@/components/execution/InspectionTracker"
import CostHistory from "@/components/execution/CostHistory"
import ExportButtons from "@/components/execution/ExportButtons"
import FileManager from "@/components/execution/FileManager"

interface ChecklistItem {
  _id: string
  label: string
  completed: boolean
  notes?: string
  dueDate?: string
}

interface ExecutionCosts {
  purchasePrice?: number
  rehabCost?: number
  holdingCosts?: number
  closingCosts?: number
  totalCosts?: number
}

interface ExecutionData {
  property?: {
    _id: string        // ✅ add this
    address: string
    city?: string
    state?: string
    zipCode?: string
  }
  phase1?: {
    arv?: {
      baseArv?: number
      finalArv?: number
      adjustmentSteps?: any[]
    }
    costs?: {
      purchasePrice?: number
      closingCosts?: number
      holdingCosts?: number
      rehabCost?: number
      totalCosts?: number
    }
  }
  workspace?: {
    _id: string
    stage: string
    uploadedBy?: string    // ✅ add this
    executionCosts?: ExecutionCosts
  }
    contractor?: {           // ✅ add this
    _id: string
  }
  checklist?: ChecklistItem[]
}

const stageConfig = {
  DUE_DILIGENCE: {
    label: "Due Diligence",
    color: "bg-blue-50 dark:bg-blue-900/30",
    textColor: "text-blue-700 dark:text-blue-300",
    borderColor: "border-blue-200 dark:border-blue-700",
  },
  BIDDING: {
    label: "Bidding",
    color: "bg-purple-50 dark:bg-purple-900/30",
    textColor: "text-purple-700 dark:text-purple-300",
    borderColor: "border-purple-200 dark:border-purple-700",
  },
  REHAB: {
    label: "Rehab",
    color: "bg-orange-50 dark:bg-orange-900/30",
    textColor: "text-orange-700 dark:text-orange-300",
    borderColor: "border-orange-200 dark:border-orange-700",
  },
  CLOSING: {
    label: "Closing",
    color: "bg-emerald-50 dark:bg-emerald-900/30",
    textColor: "text-emerald-700 dark:text-emerald-300",
    borderColor: "border-emerald-200 dark:border-emerald-700",
  },
}

const stageOrder = ["DUE_DILIGENCE", "BIDDING", "REHAB", "CLOSING"]

type TabType = "checklist" | "cost-config" | "tasks" | "contractors" | "timeline" | "inspections"

export default function ExecutionWorkspace() {
  const params = useParams()
  const propertyId = params?.propertyId as string | null
const [refreshTrigger, setRefreshTrigger] = useState(0)
  // Main Data State
  const [data, setData] = useState<ExecutionData | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [isSaving, setIsSaving] = useState(false)
  const [activeTab, setActiveTab] = useState<TabType>("checklist")
  const [error, setError] = useState<string | null>(null)
  const [isReady, setIsReady] = useState(false)
  const [checklistItems, setChecklistItems] = useState<ChecklistItem[]>([])
  
  // Cost Configuration State
  const [isEditingCosts, setIsEditingCosts] = useState(false)
  const [editedCosts, setEditedCosts] = useState<ExecutionCosts>({
    purchasePrice: 0,
    rehabCost: 0,
    holdingCosts: 0,
    closingCosts: 0,
    totalCosts: 0,
  })

  useEffect(() => {
    setIsReady(true)
  }, [])

  // Fetch main property data
  useEffect(() => {
    if (!isReady || !propertyId) return

    const fetchData = async () => {
      try {
        setIsLoading(true)
        const res = await fetch(`/api/execution/properties/${propertyId}`, {
          cache: "no-store",
        })
        
        if (!res.ok) {
          const errorData = await res.json()
          throw new Error(errorData.message || `Error ${res.status}: Failed to fetch property details`)
        }
        
        const result = await res.json()
        setData(result)
        
        if (result.checklist && checklistItems.length === 0) {
          setChecklistItems(result.checklist)
        }

        // Initialize costs from workspace.executionCosts or phase1.costs
        const workspaceCosts = result.workspace?.executionCosts
        const phase1Costs = result.phase1?.costs
        
        setEditedCosts({
          purchasePrice: workspaceCosts?.purchasePrice ?? phase1Costs?.purchasePrice ?? 0,
          rehabCost: workspaceCosts?.rehabCost ?? phase1Costs?.rehabCost ?? 0,
          holdingCosts: workspaceCosts?.holdingCosts ?? phase1Costs?.holdingCosts ?? 0,
          closingCosts: workspaceCosts?.closingCosts ?? phase1Costs?.closingCosts ?? 0,
          totalCosts: workspaceCosts?.totalCosts ?? phase1Costs?.totalCosts ?? 0,
        })
      } catch (err) {
        setError(err instanceof Error ? err.message : "An error occurred")
      } finally {
        setIsLoading(false)
      }
    }

    fetchData()
  }, [isReady, propertyId])

  // Update costs
  const handleUpdateCosts = async () => {
   let  localStorageUser = localStorage.getItem('user')
    if (!data?.workspace?._id) return

    try {
      setIsSaving(true)
      
      // Calculate total
      const total = 
        (editedCosts.purchasePrice || 0) +
        (editedCosts.rehabCost || 0) +
        (editedCosts.holdingCosts || 0) +
        (editedCosts.closingCosts || 0)

      const updatedCosts = {
        ...editedCosts,
        totalCosts: total,
      }

      const res = await fetch(`/api/execution/costs`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          workspaceId: data.workspace._id,
          executionCosts: updatedCosts,
          changedBy: localStorageUser ? JSON.parse(localStorageUser).email : "Admin",
        }),
      })

      if (!res.ok) throw new Error("Failed to update costs")

      const result = await res.json()
      
      // Update local state
      setData({
        ...data,
        workspace: {
          ...data.workspace,
          executionCosts: result.data.executionCosts,
        },
      })
      
      setEditedCosts(result.data.executionCosts)
      setIsEditingCosts(false)
      setError(null)
        setRefreshTrigger((prev) => prev + 1)

    console.log("✅ Costs updated and history refresh triggered")
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to update costs")
    } finally {
      
      setIsSaving(false)
    }
  }

  // Cancel editing
  const handleCancelEdit = () => {
    const workspaceCosts = data?.workspace?.executionCosts
    const phase1Costs = data?.phase1?.costs
    
    setEditedCosts({
      purchasePrice: workspaceCosts?.purchasePrice ?? phase1Costs?.purchasePrice ?? 0,
      rehabCost: workspaceCosts?.rehabCost ?? phase1Costs?.rehabCost ?? 0,
      holdingCosts: workspaceCosts?.holdingCosts ?? phase1Costs?.holdingCosts ?? 0,
      closingCosts: workspaceCosts?.closingCosts ?? phase1Costs?.closingCosts ?? 0,
      totalCosts: workspaceCosts?.totalCosts ?? phase1Costs?.totalCosts ?? 0,
    })
    setIsEditingCosts(false)
    setError(null)
  }

  // Stage management
  const handleStageChange = async (newStage: string) => {
    if (!data?.workspace) return

    try {
      setIsSaving(true)
      const res = await fetch("/api/execution/stage", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          workspaceId: data.workspace._id,
          stage: newStage,
        }),
      })
      if (!res.ok) throw new Error("Failed to update stage")
      setData({ ...data, workspace: { ...data.workspace, stage: newStage } })
      setError(null)
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to update stage")
    } finally {
      setIsSaving(false)
    }
  }

  // Checklist management
  const handleChecklistChange = async (itemId: string, completed: boolean) => {
    try {
      const res = await fetch("/api/execution/checklist", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          itemId,
          completed,
        }),
      })

      if (!res.ok) throw new Error("Failed to update checklist")

      setChecklistItems(prev =>
        prev.map(item =>
          item._id === itemId ? { ...item, completed } : item
        )
      )
      setError(null)

    } catch (err) {
      setError("Failed to update checklist")
    }
  }

  if (!isReady || !propertyId || isLoading) {
    return (
      <AdminLayout>
        <div className="p-8 max-w-7xl mx-auto">
          <div className="flex items-center justify-center py-24">
            <div className="text-center">
              <Loader2 className="w-12 h-12 text-blue-600 dark:text-blue-400 mx-auto mb-4 animate-spin" />
              <p className="text-gray-600 dark:text-gray-400">Loading workspace...</p>
            </div>
          </div>
        </div>
      </AdminLayout>
    )
  }

  if (!data) {
    return (
      <AdminLayout>
        <div className="p-8 max-w-7xl mx-auto">
          <div className="bg-yellow-50 dark:bg-yellow-950/50 border border-yellow-200 dark:border-yellow-800 rounded-lg p-6 flex items-center gap-3">
            <AlertCircle className="w-6 h-6 text-yellow-600 dark:text-yellow-400" />
            <p className="text-yellow-700 dark:text-yellow-300">No data found for this property</p>
          </div>
        </div>
      </AdminLayout>
    )
  }

  const currentStageIndex = stageOrder.indexOf(data.workspace?.stage || "DUE_DILIGENCE")
  const currentStageConfig = stageConfig[data.workspace?.stage as keyof typeof stageConfig]
  const completedChecklistCount = checklistItems.filter(item => item.completed).length
  const totalChecklistCount = checklistItems.length
  const checklistProgress = totalChecklistCount > 0 ? (completedChecklistCount / totalChecklistCount) * 100 : 0

  // Get current costs
  const currentCosts = data.workspace?.executionCosts || data.phase1?.costs || {}
  const displayCosts = {
    purchasePrice: currentCosts.purchasePrice || 0,
    rehabCost: currentCosts.rehabCost || 0,
    holdingCosts: currentCosts.holdingCosts || 0,
    closingCosts: currentCosts.closingCosts || 0,
    totalCosts: currentCosts.totalCosts || 0,
  }

  // Calculate total from edited costs
  const editedTotal = 
    (editedCosts.purchasePrice || 0) +
    (editedCosts.rehabCost || 0) +
    (editedCosts.holdingCosts || 0) +
    (editedCosts.closingCosts || 0)

  // Tab config
  const tabs: Array<{
    id: TabType
    label: string
    icon: React.ReactNode
    description: string
  }> = [
    {
      id: "checklist",
      label: "Checklist",
      icon: <CheckSquare className="w-4 h-4" />,
      description: "Due diligence items"
    },
    {
      id: "cost-config",
      label: "Cost Configuration",
      icon: <DollarSign className="w-4 h-4" />,
      description: "Manage project costs"
    },
    {
      id: "tasks",
      label: "Tasks",
      icon: <CheckCircle2 className="w-4 h-4" />,
      description: "Execution tasks"
    },
    {
      id: "contractors",
      label: "Contractors",
      icon: <Users className="w-4 h-4" />,
      description: "SOW & payments"
    },
    {
      id: "timeline",
      label: "Timeline",
      icon: <Calendar className="w-4 h-4" />,
      description: "Project schedule"
    },
    {
      id: "inspections",
      label: "Inspections",
      icon: <FileText className="w-4 h-4" />,
      description: "Inspections & findings"
    },
  ]

  return (
    <AdminLayout>
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900">
        <div className="p-6 lg:p-8 max-w-7xl mx-auto">
          {/* Error Alert */}
          {error && (
            <div className="mb-6 bg-red-50 dark:bg-red-950/50 border border-red-200 dark:border-red-800 rounded-lg p-4 flex items-center gap-3">
              <AlertCircle className="w-5 h-5 text-red-600 dark:text-red-400 flex-shrink-0" />
              <p className="text-red-700 dark:text-red-300 text-sm flex-1">{error}</p>
              <button 
                onClick={() => setError(null)} 
                className="text-red-600 hover:text-red-800 dark:text-red-400 dark:hover:text-red-200 transition-colors"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          )}

          {/* Back Button */}
          <div className="flex items-center justify-between mb-4">
          
          <Link href="/execution">
            <button className="flex items-center gap-2 text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 font-medium mb-6 transition-colors">
              <ArrowLeft className="w-4 h-4" />
              Back to Executions
            </button>
          </Link>
           <ExportButtons 
                propertyAddress={data.property?.address || "property"}
                propertyData={data}
                exportElementId={null}
              />   
</div>
          {/* Header */}
          <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6 mb-6">
            <div className="flex items-start justify-between mb-4">
              <div>
                <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-50 mb-2">
                  {data.property?.address}
                </h1>
                <div className="flex items-center gap-2 text-gray-600 dark:text-gray-400">
                  <MapPin className="w-4 h-4" />
                  <span className="text-sm">
                    {[data.property?.city, data.property?.state, data.property?.zipCode]
                      .filter(Boolean)
                      .join(", ")}
                  </span>
                </div>
              </div>
              
              <div className={`px-4 py-2 rounded-lg font-semibold border ${currentStageConfig?.textColor} ${currentStageConfig?.color} ${currentStageConfig?.borderColor}`}>
                {currentStageConfig?.label}
                
              </div>
           
            </div>
<div> <FileManager 
  workspaceId={data.workspace?._id || ""}
  propertyId={data.property?._id || ""}
  uploadedBy={data.workspace?.uploadedBy || "Unknown"}
  contractorId={data.contractor?._id}
/></div>
            {/* Stage Progress */}
            <div className="mt-6">
              <div className="flex items-center justify-between mb-3">
                <p className="text-sm font-semibold text-gray-700 dark:text-gray-300">Execution Progress</p>
                <p className="text-sm text-gray-600 dark:text-gray-400">{currentStageIndex + 1} of {stageOrder.length}</p>
              </div>
              <div className="w-full h-2 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
                <div
                  className="h-full bg-blue-600 dark:bg-blue-500 transition-all duration-300"
                  style={{ width: `${((currentStageIndex + 1) / stageOrder.length) * 100}%` }}
                />
              </div>
              <div className="grid grid-cols-4 gap-2 mt-4">
                {stageOrder.map((stage, index) => (
                  <div key={stage} className="flex flex-col items-center gap-2">
                    <div
                      className={`w-10 h-10 rounded-full flex items-center justify-center font-semibold text-sm transition-all ${
                        index <= currentStageIndex
                          ? "bg-blue-600 text-white dark:bg-blue-500"
                          : "bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-400"
                      }`}
                    >
                      {index < currentStageIndex ? (
                        <CheckCircle2 className="w-5 h-5" />
                      ) : (
                        <span>{index + 1}</span>
                      )}
                    </div>
                    <span className="text-xs font-medium text-gray-700 dark:text-gray-300 text-center">
                      {stageConfig[stage as keyof typeof stageConfig].label}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Quick Stats */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
            {/* Stage Selector */}
            <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
              <div className="flex items-center gap-2 mb-4">
                <Calendar className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                <h3 className="font-semibold text-gray-900 dark:text-gray-50">Update Stage</h3>
              </div>
              <div className="space-y-2">
                {stageOrder.map(stage => (
                  <button
                    key={stage}
                    onClick={() => handleStageChange(stage)}
                    disabled={isSaving}
                    className={`w-full px-4 py-2.5 rounded-lg font-medium text-sm transition-all flex items-center justify-between ${
                      data.workspace?.stage === stage
                        ? "bg-blue-600 text-white dark:bg-blue-600"
                        : "bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600"
                    }`}
                  >
                    <span>{stageConfig[stage as keyof typeof stageConfig].label}</span>
                    {data.workspace?.stage === stage && <CheckCircle2 className="w-4 h-4" />}
                  </button>
                ))}
              </div>
              {isSaving && (
                <div className="mt-3 flex items-center gap-2 text-sm text-blue-600 dark:text-blue-400">
                  <Loader2 className="w-4 h-4 animate-spin" />
                  Saving...
                </div>
              )}
            </div>

            {/* Checklist Progress */}
            <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <CheckSquare className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
                  <h3 className="font-semibold text-gray-900 dark:text-gray-50">Checklist</h3>
                </div>
                <span className="text-sm font-semibold text-gray-700 dark:text-gray-300">
                  {completedChecklistCount}/{totalChecklistCount}
                </span>
              </div>
              <div className="w-full h-3 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden mb-3">
                <div
                  className="h-full bg-emerald-600 dark:bg-emerald-500 transition-all duration-300"
                  style={{ width: `${checklistProgress}%` }}
                />
              </div>
              <p className="text-sm text-gray-600 dark:text-gray-400">
                {checklistProgress.toFixed(0)}% complete
              </p>
            </div>

            {/* Investment Summary */}
            <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
              <div className="flex items-center gap-2 mb-4">
                <DollarSign className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                <h3 className="font-semibold text-gray-900 dark:text-gray-50">Total Costs</h3>
              </div>
              <div className="text-2xl font-bold text-gray-900 dark:text-gray-50 mb-1">
                ${displayCosts.totalCosts.toLocaleString()}
              </div>
              <p className="text-sm text-gray-600 dark:text-gray-400">Project investment</p>
            </div>
          </div>

          {/* Tabs */}
          <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700">
            {/* Tab Navigation */}
            <div className="overflow-x-auto">
              <div className="flex border-b border-gray-200 dark:border-gray-700 px-6">
                {tabs.map((tab) => (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`px-4 py-3 font-medium text-sm border-b-2 transition-all whitespace-nowrap ${
                      activeTab === tab.id
                        ? "text-blue-600 dark:text-blue-400 border-blue-600 dark:border-blue-400"
                        : "text-gray-600 dark:text-gray-400 border-transparent hover:text-gray-900 dark:hover:text-gray-200"
                    }`}
                  >
                    <div className="flex items-center gap-2">
                      {tab.icon}
                      {tab.label}
                    </div>
                  </button>
                ))}
              </div>
            </div>

            {/* Tab Content */}
            <div className="p-6">
              {/* Checklist Tab */}
              {activeTab === "checklist" && (
                <div className="space-y-4">
                  <div className="mb-6">
                    <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-50 mb-4">Due Diligence Checklist</h3>
                    {checklistItems.length > 0 ? (
                      <div className="space-y-3">
                        {checklistItems.map((item) => (
                          <div
                            key={item._id}
                            className="p-4 bg-gray-50 dark:bg-gray-700/50 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                          >
                            <div className="flex items-start gap-4">
                              <button
                                onClick={() => handleChecklistChange(item._id, !item.completed)}
                                className="mt-0.5 flex-shrink-0 focus:outline-none transition-transform hover:scale-110"
                              >
                                {item.completed ? (
                                  <CheckCircle2 className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
                                ) : (
                                  <Circle className="w-5 h-5 text-gray-400 dark:text-gray-500" />
                                )}
                              </button>

                              <div className="flex-1 min-w-0">
                                <label
                                  onClick={() => handleChecklistChange(item._id, !item.completed)}
                                  className={`block cursor-pointer font-medium text-sm transition-colors ${
                                    item.completed
                                      ? "text-gray-400 dark:text-gray-500 line-through"
                                      : "text-gray-900 dark:text-gray-50"
                                  }`}
                                >
                                  {item.label}
                                </label>
                                {item.notes && (
                                  <p className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                                    {item.notes}
                                  </p>
                                )}
                                {item.dueDate && (
                                  <p className="text-xs text-gray-500 dark:text-gray-500 mt-2 flex items-center gap-1">
                                    <Calendar className="w-3 h-3" />
                                    Due: {new Date(item.dueDate).toLocaleDateString()}
                                  </p>
                                )}
                              </div>

                              <div className="flex-shrink-0">
                                <span
                                  className={`inline-block px-2.5 py-1 rounded-full text-xs font-medium ${
                                    item.completed
                                      ? "bg-emerald-100 dark:bg-emerald-900/50 text-emerald-700 dark:text-emerald-300"
                                      : "bg-gray-200 dark:bg-gray-600 text-gray-700 dark:text-gray-300"
                                  }`}
                                >
                                  {item.completed ? "Done" : "Pending"}
                                </span>
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    ) : (
                      <div className="p-12 text-center">
                        <CheckSquare className="w-12 h-12 text-gray-300 dark:text-gray-600 mx-auto mb-4" />
                        <p className="text-gray-600 dark:text-gray-400">No checklist items available</p>
                      </div>
                    )}
                  </div>
                </div>
              )}

              {/* Cost Configuration Tab */}
              {activeTab === "cost-config" && (
                <div className="space-y-6">
                  <div className="flex items-center justify-between mb-6">
                    <div>
                      <h3 className="text-xl font-bold text-gray-900 dark:text-gray-50 flex items-center gap-3">
                        <DollarSign className="w-6 h-6 text-blue-600" />
                        Cost Configuration
                      </h3>
                      <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
                        Manage and update project costs
                      </p>
                    </div>
                    {!isEditingCosts ? (
                      <button
                        onClick={() => setIsEditingCosts(true)}
                        className="px-4 py-2.5 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-lg flex items-center gap-2 hover:from-blue-700 hover:to-blue-800 transition-all font-semibold shadow-md"
                      >
                        <Edit2 className="w-4 h-4" />
                        Edit Costs
                      </button>
                    ) : (
                      <div className="flex gap-2">
                        <button
                          onClick={handleCancelEdit}
                          disabled={isSaving}
                          className="px-4 py-2.5 bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-gray-50 rounded-lg hover:bg-gray-300 dark:hover:bg-gray-600 font-semibold flex items-center gap-2 disabled:opacity-50"
                        >
                          <X className="w-4 h-4" />
                          Cancel
                        </button>
                        <button
                          onClick={handleUpdateCosts}
                          disabled={isSaving}
                          className="px-4 py-2.5 bg-gradient-to-r from-green-600 to-green-700 text-white rounded-lg flex items-center gap-2 hover:from-green-700 hover:to-green-800 transition-all font-semibold shadow-md disabled:opacity-50"
                        >
                          {isSaving ? (
                            <>
                              <Loader2 className="w-4 h-4 animate-spin" />
                              Saving...
                            </>
                          ) : (
                            <>
                              <Save className="w-4 h-4" />
                              Save Changes
                            </>
                          )}
                        </button>
                      </div>
                    )}
                  </div>

                  <div className="grid gap-6">
                    {/* Purchase Price */}
                    <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg p-5 border-2 border-gray-200 dark:border-gray-700">
                      <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-3">
                        Purchase Price
                      </label>
                      <div className="relative">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 dark:text-gray-400 font-bold text-lg">
                          $
                        </span>
                        <Input
                          type="number"
                          value={isEditingCosts ? editedCosts.purchasePrice : displayCosts.purchasePrice}
                          onChange={(e) => setEditedCosts({ ...editedCosts, purchasePrice: parseFloat(e.target.value) || 0 })}
                          disabled={!isEditingCosts}
                          className={`pl-8 text-lg font-bold ${
                            !isEditingCosts 
                              ? "bg-gray-100 dark:bg-gray-700 cursor-not-allowed" 
                              : "bg-white dark:bg-gray-800 border-blue-300 dark:border-blue-700"
                          }`}
                        />
                      </div>
                    </div>

                    {/* Rehab Cost */}
                    <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg p-5 border-2 border-gray-200 dark:border-gray-700">
                      <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-3">
                        Rehab Cost
                      </label>
                      <div className="relative">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 dark:text-gray-400 font-bold text-lg">
                          $
                        </span>
                        <Input
                          type="number"
                          value={isEditingCosts ? editedCosts.rehabCost : displayCosts.rehabCost}
                          onChange={(e) => setEditedCosts({ ...editedCosts, rehabCost: parseFloat(e.target.value) || 0 })}
                          disabled={!isEditingCosts}
                          className={`pl-8 text-lg font-bold ${
                            !isEditingCosts 
                              ? "bg-gray-100 dark:bg-gray-700 cursor-not-allowed" 
                              : "bg-white dark:bg-gray-800 border-blue-300 dark:border-blue-700"
                          }`}
                        />
                      </div>
                    </div>

                    {/* Holding Costs */}
                    <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg p-5 border-2 border-gray-200 dark:border-gray-700">
                      <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-3">
                        Holding Costs
                      </label>
                      <div className="relative">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 dark:text-gray-400 font-bold text-lg">
                          $
                        </span>
                        <Input
                          type="number"
                          value={isEditingCosts ? editedCosts.holdingCosts : displayCosts.holdingCosts}
                          onChange={(e) => setEditedCosts({ ...editedCosts, holdingCosts: parseFloat(e.target.value) || 0 })}
                          disabled={!isEditingCosts}
                          className={`pl-8 text-lg font-bold ${
                            !isEditingCosts 
                              ? "bg-gray-100 dark:bg-gray-700 cursor-not-allowed" 
                              : "bg-white dark:bg-gray-800 border-blue-300 dark:border-blue-700"
                          }`}
                        />
                      </div>
                    </div>

                    {/* Closing Costs */}
                    <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg p-5 border-2 border-gray-200 dark:border-gray-700">
                      <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-3">
                        Closing Costs
                      </label>
                      <div className="relative">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 dark:text-gray-400 font-bold text-lg">
                          $
                        </span>
                        <Input
                          type="number"
                          value={isEditingCosts ? editedCosts.closingCosts : displayCosts.closingCosts}
                          onChange={(e) => setEditedCosts({ ...editedCosts, closingCosts: parseFloat(e.target.value) || 0 })}
                          disabled={!isEditingCosts}
                          className={`pl-8 text-lg font-bold ${
                            !isEditingCosts 
                              ? "bg-gray-100 dark:bg-gray-700 cursor-not-allowed" 
                              : "bg-white dark:bg-gray-800 border-blue-300 dark:border-blue-700"
                          }`}
                        />
                      </div>
                    </div>

                    {/* Total */}
                    <div className="bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-900/20 dark:to-indigo-900/20 border-2 border-blue-300 dark:border-blue-700 rounded-lg p-6 shadow-lg">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className="p-3 bg-blue-600 rounded-lg shadow-md">
                            <DollarSign className="w-6 h-6 text-white" />
                          </div>
                          <div>
                            <p className="text-sm font-bold text-gray-700 dark:text-gray-300 uppercase tracking-wide">
                              Total Project Costs
                            </p>
                            <p className="text-xs text-gray-600 dark:text-gray-400">
                              {isEditingCosts ? "Calculated from inputs above" : "Current total investment"}
                            </p>
                          </div>
                        </div>
                        <div className="text-right">
                          <div className="text-3xl font-bold text-blue-700 dark:text-blue-300">
                            ${(isEditingCosts ? editedTotal : displayCosts.totalCosts).toLocaleString()}
                          </div>
                          {isEditingCosts && (
                            <p className="text-xs text-blue-600 dark:text-blue-400 mt-1">
                              Auto-calculated
                            </p>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Info Box */}
                  <div className="bg-blue-50 dark:bg-blue-900/20 border-l-4 border-blue-500 p-4 rounded-r-lg">
                    <div className="flex items-start gap-3">
                      <AlertCircle className="w-5 h-5 text-blue-600 dark:text-blue-400 flex-shrink-0 mt-0.5" />
                      <div className="text-sm text-blue-800 dark:text-blue-200">
                        <p className="font-semibold mb-1">Cost Configuration Info</p>
                        <p>These costs can be updated throughout the project execution phase. The total cost is automatically calculated when you save changes.</p>
                      </div>
                    </div>
                  </div>
                   <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
      <CostHistory workspaceId={data.workspace?._id}   refreshTrigger={refreshTrigger} />
    </div>
                </div>
              )}

              {/* Tasks Tab */}
              {activeTab === "tasks" && (
                <TasksManager />
              )}

              {/* Contractors Tab */}
              {activeTab === "contractors" && (
                <ContractorsManager />
              )}

              {/* Timeline Tab */}
              {activeTab === "timeline" && (
                <TimelineTracker />
              )}

              {/* Inspections Tab */}
              {activeTab === "inspections" && (
                <InspectionTracker />
              )}
            </div>
          </div>
        </div>
      </div>
    </AdminLayout>
  )
}